local function generate_token(length)
    local chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    local token = ""
    for i = 1, length do
        local random_index = math.random(1, #chars)
        token = token .. chars:sub(random_index, random_index)
    end
    return token
end

local function generate_session_token()
